 94→function ToggleSwitch({
 95→  checked,
 96→  onChange,
 97→  label,
 98→}: {
 99→  checked: boolean;
100→  onChange: (checked: boolean) => void;
101→  label: string;
102→}) {
103→  return (
104→    <label className="settings-toggle">
105→      <input
106→        type="checkbox"
107→        className="settings-toggle__input"
108→        checked={checked}
109→        onChange={e => onChange(e.target.checked)}
110→        aria-label={label}
111→      />
112→      <div className="settings-toggle__track" />
113→      <div className="settings-toggle__knob" />
114→    </label>
115→  );
116→}
