290→function ExtensionsTab({
291→  extensions,
292→  onToggle,
293→  query,
294→}: {
295→  extensions: ExtensionEntry[];
296→  onToggle: (id: string) => void;
297→  query: string;
298→}) {
299→  const filtered = useMemo(() => {
300→    if (!query) return extensions;
301→    const lower = query.toLowerCase();
302→    return extensions.filter(
303→      ext =>
304→        ext.name.toLowerCase().includes(lower) ||
305→        ext.description.toLowerCase().includes(lower) ||
306→        ext.author.toLowerCase().includes(lower),
307→    );
308→  }, [
309→    extensions,
310→    query,
311→  ]);
312→
313→  const raycastExts = filtered.filter(ext => ext.author === 'Raycast');
314→  const communityExts = filtered.filter(ext => ext.author !== 'Raycast');
315→
316→  return (
317→    <div className="settings-view__extensions">
318→      {filtered.length === 0 ? (
319→        <div
320→          className="form"
321→          style={{
322→            padding: '32px',
323→            textAlign: 'center',
324→          }}
325→        >
326→          <span style={{ color: 'var(--text-400, rgba(229, 229, 234, 0.4))' }}>
327→            No extensions match your search
328→          </span>
329→        </div>
330→      ) : (
331→        <>
332→          {raycastExts.length > 0 && (
333→            <div className="settings-section">
334→              <div className="settings-section__title">Built-in</div>
335→              {raycastExts.map(ext => (
336→                <div
337→                  key={ext.id}
338→                  className="settings-extension"
339→                  onClick={() => onToggle(ext.id)}
340→                  role="button"
341→                  tabIndex={0}
342→                  onKeyDown={e => {
343→                    if (e.key === 'Enter' || e.key === ' ') {
344→                      e.preventDefault();
345→                      onToggle(ext.id);
346→                    }
347→                  }}
348→                >
349→                  <div className="settings-extension__icon">{ext.icon()}</div>
350→                  <div className="settings-extension__info">
351→                    <div className="settings-extension__name">{ext.name}</div>
352→                    <div className="settings-extension__meta">
353→                      {ext.description}
354→                    </div>
355→                  </div>
356→                  <div className="settings-extension__toggle">
357→                    <ToggleSwitch
358→                      checked={ext.enabled}
359→                      onChange={() => onToggle(ext.id)}
360→                      label={`Toggle ${ext.name}`}
361→                    />
362→                  </div>
363→                </div>
364→              ))}
365→            </div>
366→          )}
367→          {communityExts.length > 0 && (
368→            <div className="settings-section">
369→              <div className="settings-section__title">Community</div>
370→              {communityExts.map(ext => (
371→                <div
372→                  key={ext.id}
373→                  className="settings-extension"
374→                  onClick={() => onToggle(ext.id)}
375→                  role="button"
376→                  tabIndex={0}
377→                  onKeyDown={e => {
378→                    if (e.key === 'Enter' || e.key === ' ') {
379→                      e.preventDefault();
380→                      onToggle(ext.id);
381→                    }
382→                  }}
383→                >
384→                  <div className="settings-extension__icon">{ext.icon()}</div>
385→                  <div className="settings-extension__info">
386→                    <div className="settings-extension__name">{ext.name}</div>
387→                    <div className="settings-extension__meta">
388→                      {ext.description} &middot; {ext.author}
389→                    </div>
390→                  </div>
391→                  <div className="settings-extension__toggle">
392→                    <ToggleSwitch
393→                      checked={ext.enabled}
394→                      onChange={() => onToggle(ext.id)}
395→                      label={`Toggle ${ext.name}`}
396→                    />
397→                  </div>
398→                </div>
399→              ))}
400→            </div>
401→          )}
402→        </>
403→      )}
404→    </div>
405→  );
406→}
