408→function AdvancedTab({
409→  onExport,
410→  onImport,
411→  onClearCache,
412→  onResetAll,
413→}: {
414→  onExport: () => void;
415→  onImport: () => void;
416→  onClearCache: () => void;
417→  onResetAll: () => void;
418→}) {
419→  return (
420→    <div className="settings-view__advanced">
421→      <div className="settings-section">
422→        <div className="settings-section__title">Data</div>
423→        <div
424→          className="settings-action-row"
425→          onClick={onExport}
426→          role="button"
427→          tabIndex={0}
428→          onKeyDown={e => {
429→            if (e.key === 'Enter' || e.key === ' ') {
430→              e.preventDefault();
431→              onExport();
432→            }
433→          }}
434→        >
435→          <div className="settings-action-row__icon">
436→            <ExportIcon />
437→          </div>
438→          <span className="settings-action-row__label">Export Settings</span>
439→          <span className="settings-action-row__hint">Save as JSON</span>
440→        </div>
441→        <div
442→          className="settings-action-row"
443→          onClick={onImport}
444→          role="button"
445→          tabIndex={0}
446→          onKeyDown={e => {
447→            if (e.key === 'Enter' || e.key === ' ') {
448→              e.preventDefault();
449→              onImport();
450→            }
451→          }}
452→        >
453→          <div className="settings-action-row__icon">
454→            <ImportIcon />
455→          </div>
456→          <span className="settings-action-row__label">Import Settings</span>
457→          <span className="settings-action-row__hint">Load from JSON</span>
458→        </div>
459→      </div>
460→      <div className="settings-section">
461→        <div className="settings-section__title">Maintenance</div>
462→        <div
463→          className="settings-action-row"
464→          onClick={onClearCache}
465→          role="button"
466→          tabIndex={0}
467→          onKeyDown={e => {
468→            if (e.key === 'Enter' || e.key === ' ') {
469→              e.preventDefault();
470→              onClearCache();
471→            }
472→          }}
473→        >
474→          <div className="settings-action-row__icon">
475→            <RefreshIconSmall />
476→          </div>
477→          <span className="settings-action-row__label">Clear Cache</span>
478→          <span className="settings-action-row__hint">Free up space</span>
479→        </div>
480→        <div
481→          className="settings-action-row settings-action-row--destructive"
482→          onClick={onResetAll}
483→          role="button"
484→          tabIndex={0}
485→          onKeyDown={e => {
486→            if (e.key === 'Enter' || e.key === ' ') {
487→              e.preventDefault();
488→              onResetAll();
489→            }
490→          }}
491→        >
492→          <div className="settings-action-row__icon">
493→            <TrashIconSmall />
494→          </div>
495→          <span className="settings-action-row__label">Reset All Settings</span>
496→        </div>
497→      </div>
498→    </div>
499→  );
500→}
