  4→  display: flex;
  5→  flex-direction: column;
  6→  flex: 1;
  7→  overflow-y: auto;
  8→}
  9→
 10→.settings-section {
 11→  padding: $space-3 $space-4 $space-1;
 12→
 13→  &__title {
