 88→function truncateContent(content: string, maxLength: number): string {
 89→  const singleLine = content.replace(/\n/g, ' ');
 90→  if (singleLine.length <= maxLength) return singleLine;
 91→  return singleLine.slice(0, maxLength) + '\u2026';
 92→}
