629→    [
630→      handleInsert,
631→      handleCopy,
632→      handleEdit,
633→      handleCreate,
634→      handleDelete,
635→    ],
636→  );
637→
638→  const activeDescendantId =
639→    totalItemCount > 0 ? `list-item-${selectedIndex}` : undefined;
640→
641→  if (subView !== 'list') {
642→    const formTitle = subView === 'edit' ? 'Edit Snippet' : 'Create Snippet';
643→    return (
644→      <>
645→        <SearchBar
646→          value=""
647→          onChange={() => {}}
648→          placeholder={formTitle}
649→          breadcrumbs={[
650→            ...nav.breadcrumbs,
651→            {
652→              label: 'Snippets',
653→              onBack: handleEscape,
654→            },
655→          ]}
656→        />
657→        <div className="command-palette__body">
658→          <div className="command-palette__list-container">
659→            <EditSnippetView
660→              snippet={subView === 'edit' ? editingSnippet : undefined}
661→              onSubmit={handleFormSubmit}
662→            />
663→          </div>
664→        </div>
665→        <ActionPanel
666→          contextLabel={formTitle}
667→          actions={[
668→            {
669→              label: 'Submit',
670→              shortcut: (
671→                <Kbd
672→                  keys={[
673→                    '⌘',
674→                    '↵',
675→                  ]}
676→                />
677→              ),
678→            },
679→          ]}
680→          dropdownOpen={false}
681→          dropdownSections={[]}
682→          onDropdownClose={() => {}}
683→        />
684→        <HUDContainer items={hudItems} />
685→      </>
686→    );
687→  }
688→
689→  return (
690→    <>
691→      <SearchBar
692→        value={query}
693→        onChange={handleQueryChange}
694→        placeholder="Search Snippets..."
695→        activeDescendantId={activeDescendantId}
696→        breadcrumbs={nav.breadcrumbs.length > 0 ? nav.breadcrumbs : undefined}
697→        dropdown={
698→          <SearchDropdown
699→            sections={FILTER_SECTIONS}
700→            value={filterValue}
701→            onChange={handleFilterChange}
702→          />
703→        }
704→      />
705→      <div className="command-palette__body">
706→        <div className="command-palette__list-container">
707→          {totalItemCount === 0 ? (
708→            <EmptyState
709→              icon={<SearchEmptyIcon />}
710→              title="No Snippets"
711→              description={
712→                query
713→                  ? 'Try a different search term'
714→                  : 'Create your first snippet with ⌘N'
715→              }
716→            />
717→          ) : (
718→            <List
719→              itemCount={totalItemCount}
720→              onActiveIndexChange={handleActiveIndexChange}
721→              onAction={handleInsert}
722→            >
723→              {(() => {
724→                let globalIndex = 0;
725→                const sections: ReactNode[] = [];
726→
727→                for (const group of groupedByCategory) {
728→                  sections.push(
729→                    <ListSection key={group.title} title={group.title}>
730→                      {group.items.map(entry => {
731→                        const idx = globalIndex++;
732→                        return (
733→                          <ListItem
734→                            key={entry.id}
735→                            index={idx}
736→                            icon={<SnippetHUDIcon />}
737→                            title={entry.name}
738→                            subtitle={truncateContent(entry.content, 50)}
739→                            accessories={[
740→                              ...(entry.keyword
741→                                ? [
742→                                    {
743→                                      tag: {
744→                                        text: entry.keyword,
745→                                        color: 'purple' as const,
746→                                      },
747→                                    },
748→                                  ]
749→                                : []),
750→                              ...entry.tags.map(t => ({
751→                                tag: {
752→                                  text: t.text,
753→                                  color: t.color,
754→                                },
755→                              })),
756→                              {
757→                                text: formatRelativeDate(entry.createdAt, now),
758→                                tooltip: entry.createdAt.toLocaleString(),
759→                              },
760→                            ]}
761→                          />
762→                        );
763→                      })}
764→                    </ListSection>,
765→                  );
766→                }
767→
768→                return sections;
769→              })()}
770→            </List>
771→          )}
772→        </div>
773→      </div>
774→      <ActionPanel
775→        contextLabel="Snippets"
776→        actions={[
777→          {
778→            label: 'Insert',
779→            shortcut: <Kbd keys={['↵']} />,
780→          },
781→          {
782→            label: 'Actions',
783→            shortcut: (
784→              <Kbd
785→                keys={[
786→                  '⌘',
787→                  'K',
788→                ]}
789→              />
790→            ),
791→            onClick: toggleActions,
792→          },
793→        ]}
794→        dropdownOpen={actionsOpen}
795→        dropdownSections={dropdownSections}
796→        onDropdownClose={closeActions}
797→      />
798→      {alertState && (
799→        <Alert
800→          title={alertState.title}
801→          message={alertState.message}
802→          icon={alertState.icon}
803→          primaryAction={alertState.primaryAction}
804→          dismissAction={alertState.dismissAction}
805→          onDismiss={dismissAlert}
806→        />
807→      )}
808→      <HUDContainer items={hudItems} />
809→    </>
810→  );
811→}
